import java.util.*;

public static long solve(long[][] points) {
    long mod = 1000000007L;
    long inv2 = (mod + 1) / 2;

    Map<Long, Integer> groupByY = new HashMap<>();
    for (long[] p : points) {
        long y = p[1];
        groupByY.put(y, groupByY.getOrDefault(y, 0) + 1);
    }

    long A = 0;
    long B = 0;
    for (int cnt : groupByY.values()) {
        if (cnt < 2) 
            continue;
        long c2 = (long) cnt * (cnt - 1) % mod;
        c2 = c2 * inv2 % mod;
        A = (A + c2) % mod;
        B = (B + c2 * c2) % mod;
    }

    long total = (A * A % mod - B + mod) % mod;
    total = total * inv2 % mod;
    return total;
}
```

