import java.util.*;

public class Solution {
    public static long solve(long[][] points) {
        final long mod = 1000000007L;
        long inv2 = (mod + 1) / 2;

        Map<Long, List<Long>> group = new HashMap<>();
        for (long[] p : points) {
            long x = p[0];
            long y = p[1];
            group.computeIfAbsent(y, k -> new ArrayList<>()).add(x);
        }

        long T = 0;
        long U = 0;

        for (List<Long> list : group.values()) {
            long n = list.size();
            if (n < 2) continue;

            long n_mod = n % mod;
            long a = n_mod * ((n - 1) % mod) % mod;
            a = a * inv2 % mod;

            T = (T + a) % mod;
            U = (U + a * a % mod) % mod;
        }

        long total = (T * T % mod - U + mod) % mod;
        total = total * inv2 % mod;

        return total;
    }
}
```

